/**
 * LoginForm - רכיב התחברות (D15)
 * --------------------------------
 * רכיב React להתחברות משתמשים
 * 
 * @description מימוש Pixel Perfect של דף ההתחברות בהתבסס על Blueprint של Team 31
 * @legacyReference Legacy.auth.login()
 * @blueprintSource _COMMUNICATION/team_31/team_31_staging/D15_LOGIN.html
 */

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import authService from '../../services/auth.js';
import { audit } from '../../utils/audit.js';
import { debugLog } from '../../utils/debug.js';

/**
 * LoginForm Component
 * 
 * @description רכיב התחברות עם validation, error handling, ו-loading states
 * @legacyReference Legacy.auth.login(username, password)
 */
const LoginForm = () => {
  const navigate = useNavigate();
  
  // Form state
  const [formData, setFormData] = useState({
    usernameOrEmail: '',
    password: '',
    rememberMe: true,
  });
  
  // UI state
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const [fieldErrors, setFieldErrors] = useState({});

  /**
   * Handle Input Change
   * 
   * @description מעדכן את state של הטופס
   * @param {Event} e - Event object
   */
  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    
    // Clear field error when user types
    if (fieldErrors[name]) {
      setFieldErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[name];
        return newErrors;
      });
    }
    
    // Don't clear general error immediately - let user see it
    // Error will be cleared on next form submission attempt
  };

  /**
   * Validate Form
   * 
   * @description בודק תקינות הטופס לפני שליחה
   * @returns {boolean} - true אם הטופס תקין
   */
  const validateForm = () => {
    const errors = {};
    
    if (!formData.usernameOrEmail.trim()) {
      errors.usernameOrEmail = 'שדה חובה';
    }
    
    if (!formData.password) {
      errors.password = 'שדה חובה';
    } else if (formData.password.length < 1) {
      errors.password = 'סיסמה חייבת להכיל לפחות תו אחד';
    }
    
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  /**
   * Handle Form Submit
   * 
   * @description מטפל בשליחת הטופס והתחברות
   * @param {Event} e - Event object
   */
  const handleSubmit = async (e) => {
    // CRITICAL: Always prevent default form submission
    e.preventDefault();
    e.stopPropagation();
    
    // Prevent multiple submissions
    if (isLoading) {
      return;
    }
    
    // Clear previous errors only at start of new submission
    setError(null);
    setFieldErrors({});
    
    // Validate form
    if (!validateForm()) {
      audit.log('Auth', 'Login form validation failed', { fieldErrors });
      return;
    }
    
    setIsLoading(true);
    audit.log('Auth', 'Login form submitted', { 
      usernameOrEmail: formData.usernameOrEmail,
      rememberMe: formData.rememberMe 
    });
    
    try {
      // Call Auth Service
      const response = await authService.login(
        formData.usernameOrEmail,
        formData.password
      );
      
      debugLog('Auth', 'Login successful', { userId: response.user?.externalUlids });
      
      // Store remember me preference (if needed)
      if (formData.rememberMe) {
        localStorage.setItem('remember_me', 'true');
      }
      
      // Redirect to dashboard (only on success, not on error)
      audit.log('Auth', 'Redirecting to dashboard');
      navigate('/dashboard');
      
    } catch (err) {
      // CRITICAL: Prevent any navigation or refresh on error
      // Handle error with improved error messages
      let errorMessage = 'שגיאה בהתחברות. אנא בדוק את פרטיך.';
      
      // Detect CORS or network errors
      if (err.code === 'ERR_NETWORK' || err.message === 'Network Error' || !err.response) {
        // CORS or network error - provide helpful message
        errorMessage = 'שגיאת חיבור לשרת. אנא בדוק שהשרת פועל ונסה שוב.';
        debugLog('Auth', 'Network/CORS error detected', { code: err.code, message: err.message });
      } else if (err.response) {
        // Server responded with error
        const status = err.response.status;
        
        if (status === 500) {
          errorMessage = 'שגיאת שרת פנימית. אנא נסה שוב מאוחר יותר או פנה לתמיכה.';
        } else if (status === 401) {
          // Invalid credentials - translate English messages to Hebrew
          const detail = err.response.data?.detail || '';
          if (detail.toLowerCase().includes('invalid credentials') || 
              detail.toLowerCase().includes('invalid') ||
              detail.toLowerCase().includes('credentials')) {
            errorMessage = 'שם משתמש או סיסמה שגויים. אנא נסה שוב.';
          } else if (detail) {
            // If there's a detail message, use it (assuming it's already in Hebrew from backend)
            errorMessage = detail;
          } else {
            errorMessage = 'שם משתמש או סיסמה שגויים. אנא נסה שוב.';
          }
        } else if (status === 400) {
          // Bad request - translate English messages to Hebrew
          const detail = err.response.data?.detail || '';
          if (detail.toLowerCase().includes('invalid') || 
              detail.toLowerCase().includes('bad request') ||
              detail.toLowerCase().includes('required')) {
            errorMessage = 'בקשה לא תקינה. אנא בדוק את הפרטים שהזנת.';
          } else if (detail) {
            errorMessage = detail;
          } else {
            errorMessage = 'בקשה לא תקינה. אנא בדוק את הפרטים שהזנת.';
          }
        } else if (status === 429) {
          // Rate limit
          errorMessage = 'יותר מדי ניסיונות התחברות. אנא נסה שוב מאוחר יותר.';
        } else {
          // Other server errors
          errorMessage = err.response.data?.detail || 
                        `שגיאת שרת (${status}). אנא נסה שוב מאוחר יותר.`;
        }
        
        debugLog('Auth', 'Server error response', { status, detail: err.response.data?.detail });
      } else if (err.message) {
        // Other error with message
        errorMessage = err.message;
      }
      
      // Set error state - this will trigger React re-render and show error
      // Use functional update to ensure state is set correctly
      setError(() => errorMessage);
      audit.error('Auth', 'Login failed', err);
      
      // Ensure error is visible in DOM and scroll to it
      // Use setTimeout to ensure DOM update happens after state update
      setTimeout(() => {
        const errorElement = document.querySelector('.js-error-feedback');
        if (errorElement) {
          errorElement.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }
      }, 100);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="auth-layout-root" dir="rtl">
      <tt-container>
        <tt-section>
          <div className="auth-header">
            <div className="auth-logo">
              <img src="/images/logo.svg" alt="TikTrack Logo" />
            </div>
            <p className="auth-subtitle">ברוכים הבאים ל-TikTrack</p>
            <h1 className="auth-title">התחברות</h1>
          </div>

          <form 
            className="js-login-form" 
            onSubmit={handleSubmit} 
            noValidate
            action="#"
            method="post"
          >
            {/* Error Feedback (hidden by default, shown on error) */}
            {error && (
              <div className="auth-form__error js-error-feedback" role="alert" aria-live="polite">
                {error}
              </div>
            )}

            <div className="form-group">
              <label className="form-label" htmlFor="usernameOrEmail">
                שם משתמש / אימייל:
              </label>
              <input
                type="text"
                id="usernameOrEmail"
                name="usernameOrEmail"
                className={`form-control js-login-username-input ${fieldErrors.usernameOrEmail ? 'auth-form__input--error' : ''}`}
                required
                placeholder="הכנס שם משתמש"
                value={formData.usernameOrEmail}
                onChange={handleInputChange}
                disabled={isLoading}
              />
              {fieldErrors.usernameOrEmail && (
                <span className="auth-form__error-message">{fieldErrors.usernameOrEmail}</span>
              )}
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="password">
                סיסמה:
              </label>
              <input
                type="password"
                id="password"
                name="password"
                className={`form-control js-login-password-input ${fieldErrors.password ? 'auth-form__input--error' : ''}`}
                required
                placeholder="הכנס סיסמה"
                value={formData.password}
                onChange={handleInputChange}
                disabled={isLoading}
              />
              {fieldErrors.password && (
                <span className="auth-form__error-message">{fieldErrors.password}</span>
              )}
            </div>

            <div className="form-options">
              <label className="remember-me">
                <input
                  type="checkbox"
                  name="rememberMe"
                  className="lod-checkbox js-login-remember-checkbox"
                  checked={formData.rememberMe}
                  onChange={handleInputChange}
                  disabled={isLoading}
                />
                {' '}זכור אותי
              </label>
              <Link to="/reset-password" className="auth-link js-forgot-password-link">
                שכחת סיסמה?
              </Link>
            </div>

            <button
              type="submit"
              className="btn-auth-primary js-login-submit-button"
              disabled={isLoading}
            >
              {isLoading ? 'מתחבר...' : 'התחבר'}
            </button>
          </form>

          <div className="auth-footer-zone">
            <span>אין לך חשבון?</span>{' '}
            <Link to="/register" className="auth-link-bold js-register-link">
              הרשמה עכשיו
            </Link>
          </div>
        </tt-section>
      </tt-container>
    </div>
  );
};

export default LoginForm;
