/**
 * ProfileView - עמוד ניהול פרופיל משתמש (D15)
 * --------------------------------------------
 * עמוד ניהול פרופיל המשתמש המחובר
 * 
 * @description מימוש Pixel Perfect של עמוד הפרופיל בהתבסס על Blueprint של Team 31
 * @legacyReference Legacy.user.profile()
 * @blueprintSource _COMMUNICATION/team_01/team_01_staging/D15_PROF_VIEW.html
 */

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import authService from '../../services/auth.js';
import { audit } from '../../utils/audit.js';
import { debugLog } from '../../utils/debug.js';

/**
 * ProfileView Component
 * 
 * @description עמוד ניהול פרופיל המשתמש המחובר
 * @legacyReference Legacy.user.profile()
 */
const ProfileView = () => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    /**
     * טעינת נתוני המשתמש הנוכחי
     */
    const loadUserData = async () => {
      try {
        debugLog('ProfileView', 'Loading user data');
        const userData = await authService.getCurrentUser();
        debugLog('ProfileView', 'User data loaded', { 
          userId: userData.externalUlids, 
          username: userData.username 
        });
        setCurrentUser(userData);
      } catch (error) {
        debugLog('ProfileView', 'Failed to load user data', error);
        audit.error('ProfileView', 'Failed to load user data', error);
      } finally {
        setLoading(false);
      }
    };

    loadUserData();
  }, []);

  if (loading) {
    return (
      <div className="auth-layout-root" dir="rtl">
        <tt-container>
          <tt-section>
            <div style={{ textAlign: 'center', padding: '2rem' }}>
              <p>טוען...</p>
            </div>
          </tt-section>
        </tt-container>
      </div>
    );
  }

  return (
    <div className="auth-layout-root" dir="rtl">
      <tt-container>
        <tt-section>
          <div className="auth-header">
            <div className="auth-logo">
              <img src="/images/logo.svg" alt="TikTrack Logo" />
            </div>
            <p className="auth-subtitle">ניהול הפרופיל שלך</p>
            <h1 className="auth-title">פרופיל משתמש</h1>
          </div>

          {/* User Info Section */}
          {currentUser && (
            <div style={{ 
              padding: '1.5rem', 
              marginBottom: '2rem',
              backgroundColor: 'var(--color-5, #f4f7f9)',
              borderRadius: '8px',
              border: '1px solid var(--border-color, #C6C6C8)'
            }}>
              <h2 style={{ fontSize: '1.1rem', marginBottom: '1rem', color: 'var(--text-primary, #000)' }}>פרטי משתמש</h2>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                {currentUser.username && (
                  <p style={{ margin: 0 }}>
                    <strong>שם משתמש:</strong> {currentUser.username}
                  </p>
                )}
                {currentUser.email && (
                  <p style={{ margin: 0 }}>
                    <strong>אימייל:</strong> {currentUser.email}
                  </p>
                )}
                {currentUser.displayName && (
                  <p style={{ margin: 0 }}>
                    <strong>שם תצוגה:</strong> {currentUser.displayName}
                  </p>
                )}
                {currentUser.role && (
                  <p style={{ margin: 0 }}>
                    <strong>תפקיד:</strong> {currentUser.role}
                  </p>
                )}
              </div>
            </div>
          )}

          {/* Password Change Link */}
          <div style={{ marginTop: '2rem', paddingTop: '2rem', borderTop: '1px solid var(--border-color, #C6C6C8)', textAlign: 'center' }}>
            <Link 
              to="/profile/password"
              className="btn-auth-primary"
              style={{ 
                display: 'inline-block',
                padding: '0.75rem 1.5rem',
                textDecoration: 'none',
                borderRadius: 'var(--pico-border-radius)',
                fontSize: '1rem'
              }}
            >
              שינוי סיסמה
            </Link>
          </div>

          {/* Navigation Links */}
          <div className="auth-footer-zone" style={{ marginTop: '2rem', textAlign: 'center' }}>
            <Link to="/" className="auth-link js-back-to-home-link">
              חזרה לעמוד הבית
            </Link>
          </div>
        </tt-section>
      </tt-container>
    </div>
  );
};

export default ProfileView;
